questions.answer:
Store notes in AsyncStorage as `{id, text, ts, synced}`. On startup, load local notes. Use NetInfo to watch connectivity; when online, push notes with `synced=false` to the server via POST /notes, then mark them as `synced=true` on success.

```javascript
import AsyncStorage from '@react-native-async-storage/async-storage';
import NetInfo from '@react-native/netinfo';

const STORAGE_KEY = '@notes';

const NoteService = {
  async load() {
    const data = await AsyncStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  async save(note) {
    const notes = await this.load();
    const updated = { ...note, ts: Date.now(), synced: false };
    const idx = notes.findIndex(n => n.id === note.id);
    idx >= 0 ? notes[idx] = updated : notes.push(updated);
    await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(notes));
    this.trySync();
    return updated;
  },

  async sync() {
    const notes = await this.load();
    const pending = notes.filter(n => !n.synced);
    for (const note of pending) {
      try {
        await fetch('https://api.example.com/notes', {
          method: 'POST',
          body: JSON.stringify({ id: note.id, text: note.text, ts: note.ts }),
          headers: { 'Content-Type': 'application/json' },
        });
        note.synced = true;
      } catch (e) {
        break; // stop on first failure, retry later
      }
    }
    await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(notes));
  },

  trySync() {
    NetInfo.fetch().then(state => {
      if (state.isConnected) this.sync();
    });
  },
};

// Usage
const note = await NoteService.save({ id: '1', text: 'My note' });
const notes = await NoteService.load();
```

**Conflict handling:** Server uses last-writer-wins with `ts`. Each note carries a timestamp; if server has a newer `ts`, it ignores the client write.

