```javascript
import React, { useState, useRef, useCallback } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  Animated,
  Platform,
  UIManager,
  LayoutAnimation,
  UIManager,
} from 'react-native';

if (Platform.OS === 'android' && UIManager.setLayoutAnimationEnabledExperimental) {
  UIManager.setLayoutAnimationEnabledExperimental(true);
}

const AccordionItem = ({ title, children, isExpanded, onToggle, animatedHeight }) => {
  const contentRef = useRef(null);

  return (
    <View>
      <TouchableOpacity
        onPress={onToggle}
        accessibilityRole="button"
        accessibilityState={{ expanded: isExpanded }}
        accessibilityLabel={`${title}, collapsed. Tap to expand.`}
        style={{ padding: 16, backgroundColor: '#f5f5f5' }}
      >
        <Text style={{ fontWeight: '600' }}>{title}</Text>
      </TouchableOpacity>

      <Animated.View
        style={{ height: animatedHeight, overflow: 'hidden' }}
        accessibilityRole="region"
        accessibilityLabel={`${title} content`}
        accessibilityState={{ hidden: !isExpanded }}
      >
        <View ref={contentRef} style={{ padding: 16 }}>
          {children}
        </View>
      </Animated.View>
    </View>
  );
};

const Accordion = ({ sections }) => {
  const [openIndex, setOpenIndex] = useState(null);
  const [measuredHeights, setMeasuredHeights] = useState({});

  const animatedValues = useRef(
    sections.map(() => new Animated.Value(0))
  ).current;

  const toggleSection = useCallback((index) => {
    const willOpen = openIndex !== index;
    const newIndex = willOpen ? index : null;

    LayoutAnimation.configureNext(LayoutAnimation.Presets.easeInEaseOut);
    setOpenIndex(newIndex);

    sections.forEach((_, i) => {
      const targetValue = newIndex === i ? 1 : 0;
      Animated.spring(animatedValues[i], {
        toValue: targetValue,
        useNativeDriver: false,
        friction: 8,
      }).start();
    });
  }, [openIndex, animatedValues, sections]);

  const handleContentLayout = (index) => (event) => {
    if (!measuredHeights[index]) {
      const height = event.nativeEvent.layout.height;
      setMeasuredHeights(prev => ({ ...prev, [index]: height }));
    }
  };

  return (
    <View>
      {sections.map((section, index) => (
        <AccordionItem
          key={index}
          title={section.title}
          isExpanded={openIndex === index}
          onToggle={() => toggleSection(index)}
          animatedHeight={animatedValues[index].interpolate({
            inputRange: [0, 1],
            outputRange: [0, measuredHeights[index] || 1],
          })}
          onContentLayout={handleContentLayout(index)}
        >
          <View onLayout={handleContentLayout(index)}>
            {section.content}
          </View>
        </AccordionItem>
      ))}
    </View>
  );
};

// Usage
const sections = [
  { title: 'Getting Started', content: 'Welcome to our app. This guide will help you get up and running quickly.' },
  { title: 'Features', content: 'Our app includes real-time sync, offline support, and customizable themes.' },
  { title: 'Pricing', content: 'Free tier: limited features. Pro: $9.99/month with unlimited access.' },
];

export default function App() {
  return <Accordion sections={sections} />;
}
```

