import React, {useEffect, useState} from 'react';
import {FlatList, TextInput, View, Text, RefreshControl} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const RestaurantsList = () => {
  const [restaurants, setRestaurants] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState('');
  const [refreshing, setRefreshing] = useState(false);

  const fetchRestaurants = async (forceRefresh = false) => {
    const cacheKey = 'restaurants_v1';

    if (!forceRefresh) {
      const cached = await AsyncStorage.getItem(cacheKey);
      if (cached) {
        const {data} = JSON.parse(cached);
        setRestaurants(data);
        setFiltered(data);
      }
    }

    const response = await fetch('https://api.example.com/restaurants');
    const data = await response.json();

    await AsyncStorage.setItem(cacheKey, JSON.stringify({data, timestamp: Date.now()}));
    setRestaurants(data);
    setFiltered(search ? data.filter(r => r.name.toLowerCase().includes(search.toLowerCase())) : data);
    setRefreshing(false);
  };

  useEffect(() => { fetchRestaurants(); }, []);

  const handleSearch = (text) => {
    setSearch(text);
    setFiltered(restaurants.filter(r => r.name.toLowerCase().includes(text.toLowerCase())));
  };

  return (
    <View>
      <TextInput placeholder="Search restaurants..." value={search} onChangeText={handleSearch} />
      <FlatList
        data={filtered}
        keyExtractor={(item) => item.id}
        renderItem={({item}) => <Text>{item.name}</Text>}
        refreshControl={<RefreshControl refreshing={refreshing} onRefresh={() => { setRefreshing(true); fetchRestaurants(true); }} />}
      />
    </View>
  );
};

export default RestaurantsList;
```

