## Code Example
```javascript
// LocalAuditLog.ts (sketch)
import { open } from 'sqlite';
import sqlite3 from 'sqlite3';
import nacl from 'tweetnacl';
import naclUtil from 'tweetnacl-util';

type AuditRecord = {
  id: string;
  tenantId: string;
  timestamp: number;
  nonce: string;
  payload: string;
  hash?: string;
  signature?: string;
};

export class LocalAuditLog {
  private db: any;
  private keyPair: { publicKey: string; secretKey: string };

  private constructor(db: any, keyPair: { publicKey: string; secretKey: string }) {
    this.db = db; this.keyPair = keyPair;
  }

  static async create(dbPath: string): Promise<LocalAuditLog> {
    const db = await open({ filename: dbPath, driver: sqlite3.Database });
    await db.exec(`CREATE TABLE IF NOT EXISTS audits (
      id TEXT PRIMARY KEY, tenantId TEXT, timestamp INTEGER, nonce TEXT,
      payload TEXT, hash TEXT, signature TEXT, sent INTEGER DEFAULT 0
    )`);
    // placeholder keypair; in practice load from secure storage and rotate as needed
    const keyPair = nacl.sign.keyPair();
    return new LocalAuditLog(db, {
      publicKey: naclUtil.encodeBase64(keyPair.publicKey),
      secretKey: naclUtil.encodeBase64(keyPair.secretKey)
    });
  }

  async append(tenantId: string, payload: string, nonce: string): Promise<void> {
    const record: AuditRecord = {
      id: crypto.randomUUID(), tenantId, timestamp: Date.now(), nonce, payload
    };
    const data = `${record.tenantId}|${record.timestamp}|${record.nonce}|${record.payload}`;
    const sig = nacl.sign.detached(naclUtil.decodeBase64(this.keyPair.secretKey), naclUtil.decodeUTF8(data));
    record.hash = this.hashRecord(record);
    record.signature = naclUtil.encodeBase64(sig);
    await this.db.run(`INSERT INTO audits (id, tenantId, timestamp, nonce, payload, hash, signature) VALUES (?, ?, ?, ?, ?, ?, ?)`,
      record.id, record.tenantId, record.timestamp, record.nonce, record.payload, record.hash, record.signature);
  }

  async getBatch(limit: number): Promise<AuditRecord[]> {
    const rows = await this.db.all(`SELECT * FROM audits WHERE sent = 0 ORDER BY timestamp ASC LIMIT ?`, limit);
    return rows as AuditRecord[];
  }

  async markSent(ids: string[]): Promise<void> {
    const placeholders = ids.map(() => '?').join(',');
    await this.db.run(`UPDATE audits SET sent = 1 WHERE id IN (${placeholders})`, ids);
  }

  private hashRecord(r: AuditRecord): string {
    return naclUtil.crypto_hash(`${r.tenantId}|${r.timestamp}|${r.nonce}|${r.payload}`);
  }
}
```

