## Code Example
```java
// Android - FrameSamplerModule.kt (TurboModule)
@ReactModule(name = FrameSamplerModule.NAME)
class FrameSamplerModule(reactContext: ReactApplicationContext) :
    NativeFrameSamplerSpec(reactContext) {

    companion object { const val NAME = "FrameSampler" }

    private val handlerThread = HandlerThread("FrameSampler").apply { start() }
    private val samplerHandler = Handler(handlerThread.looper)
    private val ringBuffer = RingBuffer<FrameEvent>(capacity = 300)
    private var isSampling = false
    private var privacyFilterEnabled = true

    private val frameCallback = object : Choreographer.FrameCallback {
        override fun doFrame(frameTimeNanos: Long) {
            if (isSampling) {
                collectFrameData(frameTimeNanos)
                samplerHandler.postDelayed(this, 10_000_000) // ~100Hz
            }
        }
    }

    override fun startSampling(options: SampleOptions) {
        privacyFilterEnabled = options.enablePrivacyFilter
        isSampling = true
        Choreographer.getInstance().postFrameCallback(frameCallback)
    }

    override fun stopSampling() {
        isSampling = false
        Choreographer.getInstance().removeFrameCallback(frameCallback)
    }

    override fun getSamples(): List<FrameEvent> {
        return ringBuffer.drain().filter { !privacyFilterEnabled || !it.containsPII }
    }

    override fun invalidate() {
        stopSampling()
        handlerThread.quitSafely()
        super.invalidate()
    }
}
```

```swift
// iOS - FrameSamplerModule.swift (TurboModule)
@objc(FrameSampler)
class FrameSamplerModule: NSObject, FrameSamplerSpec {

    private let samplerQueue = DispatchQueue(label: "com.app.framesampler", qos: .userInteractive)
    private var displayLink: CADisplayLink?
    private var ringBuffer = RingBuffer<FrameEvent>(capacity: 300)
    private var isSampling = false
    private var privacyFilterEnabled = true

    @objc func startSampling(_ options: NSDictionary) {
        privacyFilterEnabled = options["enablePrivacyFilter"] as? Bool ?? true
        isSampling = true

        displayLink = CADisplayLink(target: self, selector: #selector(onFrame))
        displayLink?.preferredFrameRateRange = CAFrameRateRange(minimum: 60, maximum: 120, preferred: 100)
        displayLink?.add(to: .main, forMode: .common)
    }

    @objc func stopSampling() {
        isSampling = false
        displayLink?.invalidate()
        displayLink = nil
    }

    @objc func getSamples(_ resolve: @escaping RCTPromiseResolveBlock,
                          reject: @escaping RCTPromiseRejectBlock) {
        samplerQueue.async { [weak self] in
            let samples = self?.ringBuffer.drain() ?? []
            let filtered = samples.filter { !$0.containsPII || !(self?.privacyFilterEnabled ?? true) }
            resolve(filtered.map { $0.toDictionary() })
        }
    }

    @objc func invalidate() {
        stopSampling()
    }

    @objc private func onFrame(_ displayLink: CADisplayLink) {
        guard isSampling else { return }
        let event = FrameEvent(
            timestamp: displayLink.timestamp,
            vsync: displayLink.targetTimestamp - displayLink.timestamp,
            inputLatency: measureInputLatency(),
            gpuTime: getGPUTimestamp()
        )
        ringBuffer.append(event)
    }
}
```

```typescript
// Usage in JS
import { NativeModules } from 'react-native';
const { FrameSampler } = NativeModules;

function useFrameSampler() {
  const [samples, setSamples] = useState([]);

  const startProfiling = useCallback(() => {
    FrameSampler.startSampling({ enablePrivacyFilter: true });
    const interval = setInterval(() => {
      setSamples(FrameSampler.getSamples());
    }, 100);
    return () => clearInterval(interval);
  }, []);

  const stopProfiling = useCallback(() => {
    FrameSampler.stopSampling();
  }, []);

  useEffect(() => {
    const cleanup = startProfiling();
    return () => { stopProfiling(); cleanup?.(); };
  }, [startProfiling, stopProfiling]);

  return { samples, startProfiling, stopProfiling };
}
```

