import React, {useEffect, useState, useCallback} from 'react';
import {FlatList, View, Text, Image, RefreshControl} from 'react-native';

export default function UsersList(){ 
  const [data,setData] = useState([]);
  const [loading,setLoading] = useState(false);
  const [refreshing,setRefreshing] = useState(false);
  const [page,setPage] = useState(1);
  const [error,setError] = useState(null);

  const fetchUsers = async (pageNum=1, refresh=false) => {
     try {
        if (refresh) setRefreshing(true);
        else setLoading(true);
        const res = await fetch(`https://api.example.com/users?page=${pageNum}`);
        const json = await res.json();
        setData(prev => refresh ? json : [...prev, ...json]);
        setError(null);
     } catch (e) { setError(e); }
     finally { setLoading(false); setRefreshing(false); }
  };

  useEffect(()=>{ fetchUsers(); },[]);

  const onRefresh = () => fetchUsers(1,true);
  const onEndReached = () => { fetchUsers(page+1); setPage(p=>p+1); };

  return (
    <FlatList
      data={data}
      keyExtractor={item => String(item.id)}
      numColumns={2}
      renderItem={({item}) => (
        <View style={{flex:1, padding:8}}>
          <Image source={{uri:item.avatar}} style={{width:60,height:60,borderRadius:30}}/>
          <Text>{item.name}</Text>
        </View>
      )}
      refreshControl={<RefreshControl refreshing={refreshing} onRefresh={onRefresh} />}
      onEndReached={onEndReached}
      onEndReachedThreshold={0.5}
      ListEmptyComponent={<Text>{error ? "Error loading" : "No data"}</Text>}
