## Code Example

```javascript
import { useEffect, useState, useCallback } from 'react';
import { FlatList, RefreshControl, Text, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const CACHE_PREFIX = 'feed_cache_';

function useFeed(url) {
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState(null);
  const [error, setError] = useState(null);

  const fetchData = useCallback(async (isRefresh = false) => {
    if (!isRefresh) setLoading(true);
    setError(null);

    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const json = await response.json();

      await AsyncStorage.setItem(CACHE_PREFIX + url, JSON.stringify(json));
      setData(json);
    } catch (err) {
      const cached = await AsyncStorage.getItem(CACHE_PREFIX + url);
      if (cached) {
        setData(JSON.parse(cached));
      } else {
        setError(err.message);
      }
    } finally {
      setLoading(false);
    }
  }, [url]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const refresh = useCallback(() => fetchData(true), [fetchData]);

  return { loading, data, error, refresh };
}

// Usage
function FeedScreen() {
  const { loading, data, error, refresh } = useFeed('https://api.example.com/posts');

  if (loading && !data) return <Text>Loading...</Text>;
  if (error && !data) return <Text>Error: {error}</Text>;

  return (
    <FlatList
      data={data}
      keyExtractor={item => item.id.toString()}
      renderItem={({ item }) => <Text>{item.title}</Text>}
      refreshControl={<RefreshControl refreshing={loading} onRefresh={refresh} />}
    />
  );
}
```

