## Code Example
```javascript
import {useEffect, useState, useCallback} from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import NetInfo from '@react-native-community/netinfo';

export function useImageList(endpoint) {
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const load = useCallback(async (force = false) => {
    if (!force) {
      const cached = await AsyncStorage.getItem('images_cache');
      if (cached) {
        setImages(JSON.parse(cached));
        setLoading(false);
        return;
      }
    }
    try {
      const res = await fetch(endpoint);
      const data = await res.json();
      setImages(data);
      await AsyncStorage.setItem('images_cache', JSON.stringify(data));
      await AsyncStorage.setItem('images_cache_ts', Date.now().toString());
      setError(null);
    } catch (e) {
      setError(e);
    } finally {
      setLoading(false);
    }
  }, [endpoint]);

  useEffect(() => {
    load();
    const unsubscribe = NetInfo.addEventListener(state => {
      if (state.isConnected) load(true);
    });
    return () => unsubscribe();
  }, [load]);

  return { images, loading, error, retry: () => load(true) };
}
```

