## Code Example
```javascript
import React, {useState, useCallback} from 'react';
import {FlatList, Text, View, ActivityIndicator, TouchableOpacity, StyleSheet} from 'react-native';

const ITEM_HEIGHT = 80;

const FeedList = ({initialData = []}) => {
  const [data, setData] = useState(initialData);
  const [refreshing, setRefreshing] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);

  const fetchMore = useCallback(async () => {
    if (loading) return;
    setLoading(true);
    try {
      const newData = await fetchData(page + 1);
      setData(prev => [...prev, ...newData]);
      setPage(prev => prev + 1);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [page, loading]);

  const handleRefresh = useCallback(async () => {
    setRefreshing(true);
    try {
      const freshData = await fetchData(1);
      setData(freshData);
      setPage(1);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setRefreshing(false);
    }
  }, []);

  const retry = useCallback(() => {
    setError(null);
    fetchMore();
  }, [fetchMore]);

  const renderItem = useCallback(({item}) => (
    <FeedItem item={item} />
  ), []);

  const keyExtractor = useCallback(item => String(item.id), []);

  const getItemLayout = useCallback((_, index) => ({
    length: ITEM_HEIGHT,
    offset: ITEM_HEIGHT * index,
    index,
  }), []);

  if (error && data.length === 0) {
    return (
      <View style={styles.errorContainer}>
        <Text style={styles.errorText}>{error}</Text>
        <TouchableOpacity onPress={retry} style={styles.retryButton}>
          <Text style={styles.retryText}>Retry</Text>
        </TouchableOpacity>
      </View>
    );
  }

  return (
    <FlatList
      data={data}
      renderItem={renderItem}
      keyExtractor={keyExtractor}
      getItemLayout={getItemLayout}
      onRefresh={handleRefresh}
      refreshing={refreshing}
      onEndReached={fetchMore}
      onEndReachedThreshold={0.5}
      ItemSeparatorComponent={() => <View style={styles.separator} />}
      ListFooterComponent={loading ? <ActivityIndicator /> : null}
    />
  );
};

const styles = StyleSheet.create({
  errorContainer: {flex: 1, justifyContent: 'center', alignItems: 'center', padding: 20},
  errorText: {color: 'red', marginBottom: 10},
  retryButton: {padding: 10, backgroundColor: '#007AFF', borderRadius: 5},
  retryText: {color: 'white'},
  separator: {height: 1, backgroundColor: '#eee'},
});

export default FeedList;
```

