import { useEffect, useState } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import NetInfo from '@react-native-community/netinfo';

export const useOfflineQueue = (storageKey = 'offline_submissions') => {
  const [queue, setQueue] = useState([]);
  useEffect(() => {
    (async () => {
      const raw = await AsyncStorage.getItem(storageKey);
      setQueue(raw ? JSON.parse(raw) : []);
    })();
  }, [storageKey]);

  const enqueue = async (payload) => {
    const item = { id: `${Date.now()}-${Math.random()}`, payload, timestamp: Date.now(), retries: 0 };
    const next = [...queue, item];
    setQueue(next);
    await AsyncStorage.setItem(storageKey, JSON.stringify(next));
  };

  const flush = async () => {
    if (!queue.length) return;
    const toSend = queue.map(i => i.payload);
    try {
      const res = await fetch('https://example.com/api/submissions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(toSend),
      });
      if (res.ok) {
        await AsyncStorage.setItem(storageKey, JSON.stringify([]));
        setQueue([]);
      } else {
        throw new Error('server-error');
      }
    } catch (e) {
      const advanced = queue.map(i => ({ ...i, retries: i.retries + 1 }));
      setQueue(advanced);
      await AsyncStorage.setItem(storageKey, JSON.stringify(advanced));
    }
  };

  return { queue, enqueue, flush };
};
```

