## Code Example

```javascript
function createFeed({ endpoint, pageSize = 20, cacheKey }) {
  let items = [];
  let page = 1;
  const listeners = new Set();

  const notify = () => listeners.forEach(cb => cb(items));

  const loadFromCache = async () => {
    const cached = await AsyncStorage.getItem(cacheKey);
    return cached ? JSON.parse(cached) : [];
  };

  const persistToCache = async (data) => {
    const toCache = data.slice(-50);
    await AsyncStorage.setItem(cacheKey, JSON.stringify(toCache));
  };

  return {
    async refresh() {
      const cached = await loadFromCache();
      items = cached;
      notify();

      const res = await fetch(`${endpoint}?page=1&limit=${pageSize}`);
      const newItems = await res.json();
      items = newItems;
      await persistToCache(items);
      notify();
    },
    async loadMore() {
      page++;
      const res = await fetch(`${endpoint}?page=${page}&limit=${pageSize}`);
      const newItems = await res.json();
      items = [...items, ...newItems];
      await persistToCache(items);
      notify();
    },
    onItemsChange(cb) {
      listeners.add(cb);
      return () => listeners.delete(cb);
    },
  };
}
```

