## Code Example
```javascript
import { useEffect, useState, useCallback } from 'react'
import NetInfo from '@react-native-community/netinfo'
import { PixelRatio } from 'react-native'

function useAdaptiveImage(sizes, baseUri) {
  const [uri, setUri] = useState(sizes.medium)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  const resolveVariant = useCallback((info) => {
    const bandwidth = info.type === 'wifi' ? 1000 : info.details?.speed ?? 500
    const dpr = PixelRatio.get()
    const batterySaver = info.batterySaverEnabled
    let chosen = sizes.medium
    if (!batterySaver && bandwidth > 800 && dpr >= 2) chosen = sizes.large
    else if (bandwidth < 400) chosen = sizes.thumb
    return chosen
  }, [sizes])

  useEffect(() => {
    let mounted = true
    NetInfo.fetch().then(info => {
      if (!mounted) return
      const variant = resolveVariant(info)
      setUri(variant)
      // pretend fetch/cache logic here
      setLoading(false)
    }).catch(err => {
      if (mounted) { setError(err); setLoading(false) }
    })
    return () => { mounted = false }
  }, [resolveVariant])

  const refresh = useCallback(() => {
    setLoading(true)
    NetInfo.fetch().then(info => {
      const variant = resolveVariant(info)
      setUri(variant)
      setLoading(false)
    }).catch(err => setError(err))
  }, [resolveVariant])

  return { uri, loading, error, refresh }
}
```

