import React, {useEffect, useState} from 'react';
import {FlatList, View, Text, Button, ActivityIndicator, RefreshControl} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

export default function StockList({endpoint = '/api/stocks', storageKey = 'stocks_cache'}) {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  useEffect(() => { loadCache(); fetchData(); }, []);

  async function loadCache() {
    try { const cached = await AsyncStorage.getItem(storageKey); if (cached) setData(JSON.parse(cached)); } catch {}
  }

  async function fetchData() {
    setLoading(true);
    try {
      const res = await fetch(endpoint);
      const json = await res.json();
      setData(json);
      await AsyncStorage.setItem(storageKey, JSON.stringify(json));
    } catch {
      // keep existing data
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }

  function renderItem({item}) { return (
    <View><Text>{item.symbol} — {item.price}</Text></View>
  ); }

  return (
    data.length ? (
      <FlatList data={data} keyExtractor={i => i.symbol} renderItem={renderItem}
        refreshControl={<RefreshControl refreshing={refreshing} onRefresh={() => { setRefreshing(true); fetchData(); }} />} />
    ) : (
      loading ? <ActivityIndicator /> : <Text>No data</Text>
    )
  );
}
```

