import { useEffect, useRef, useState } from 'react';
import { NativeEventEmitter, NativeModules } from 'react-native';

export function useLiveList(channel) {
  const [updates, setUpdates] = useState([]);
  const buf = useRef([]);

  useEffect(() => {
    const emitter = new NativeEventEmitter(NativeModules[channel]);
    const subscription = emitter.addListener('dataUpdate', (data) => {
      buf.current.push(data);
    });

    const flushInterval = setInterval(() => {
      if (buf.current.length > 0) {
        setUpdates(prev => [...prev, ...buf.current]);
        buf.current = [];
      }
    }, 16); // ~60fps

    return () => {
      subscription.remove();
      clearInterval(flushInterval);
    };
  }, [channel]);

  return updates;
}

