// Minimal sketch: useLiveCatalog hook
import { useEffect, useRef, useState } from 'react';
function useLiveCatalog(url) {
  const [items, setItems] = useState(new Map());
  const batch = useRef([]);
  useEffect(() => {
    const ws = new WebSocket(url);
    ws.onmessage = (ev) => {
      batch.current.push(JSON.parse(ev.data));
    };
    const t = setInterval(() => {
      if (!batch.current.length) return;
      const next = new Map(items);
      for (const it of batch.current) next.set(it.id, it);
      setItems(next);
      batch.current = [];
    }, 16);
    return () => clearInterval(t);
  }, [url]);
  return Array.from(items.values());
}
