import { useState, useEffect } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';

export function useCacheList(endpoint) {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        // Load cached data first
        const cached = await AsyncStorage.getItem(`cache_${endpoint}`);
        if (cached) {
          setData(JSON.parse(cached));
        }

        // Fetch fresh data
        const response = await fetch(endpoint);
        const freshData = await response.json();

        // Merge by id, preserving cached order
        const merged = mergeById(data, freshData);
        setData(merged);

        // Update cache
        await AsyncStorage.setItem(`cache_${endpoint}`, JSON.stringify(merged));
      } catch (err) {
        setError(err);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [endpoint]);

  return { data, loading, error, refetch: () => loadData() };
}

function mergeById(cached, fresh) {
  const map = new Map();

  // Preserve cached order
  cached.forEach(item => map.set(item.id, item));

  // Update with fresh data
  fresh.forEach(item => {
    if (map.has(item.id)) {
      map.set(item.id, item);
    } else {
      // Append new items
      cached.push(item);
    }
  });

  return Array.from(map.values());
}
```

