import React, {createContext, useContext, useState, useEffect} from 'react'

const defaultTheme = {
  background: '#ffffff', text: '#000000', primary: '#1f6feb'
}

const ThemeContext = createContext(defaultTheme)

export const ThemeProvider = ({children}) => {
  const colorScheme = useColorScheme()
  const [theme, setTheme] = useState(defaultTheme)

  useEffect(() => {
    const load = async () => {
      const saved = await AsyncStorage.getItem('app_theme')
      if (saved) setTheme(JSON.parse(saved))
      else if (colorScheme === 'dark') setTheme({background: '#000000', text: '#ffffff', primary: '#4dabf7'})
    }
    load()
  }, [])

  const toggle = async () => {
    const next = theme.background === '#ffffff'
      ? {background: '#000000', text: '#ffffff', primary: '#4dabf7'}
      : {background: '#ffffff', text: '#000000', primary: '#1f6feb'}
    setTheme(next)
    await AsyncStorage.setItem('app_theme', JSON.stringify(next))
  }

  return (
    <ThemeContext.Provider value={{theme, toggle}}>
      {children}
    </ThemeContext.Provider>
  )
}

export const ThemedButton = ({title, onPress}) => {
  const {theme} = useContext(ThemeContext)
  return (
    <TouchableOpacity onPress={onPress} style={{backgroundColor: theme.primary, padding: 12, borderRadius: 6}}>
      <Text style={{color: theme.text}}>{title}</Text>
    </TouchableOpacity>
  )
}
