function useLocationWithBatteryGuard() {
  const [coords, setCoords] = useState(null);
  useEffect(() => {
    let interval = null;
    const determineInterval = async () => {
      const lvl = await getBatteryLevel();
      if (lvl > 0.8) return 1000;
