## Code Example
```javascript
// useNearbyBikes.ts
export function useNearbyBikes() {
  const [bikes, setBikes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const STORAGE_KEY = '@nearby_bikes';

  const loadCached = async () => {
    const cached = await AsyncStorage.getItem(STORAGE_KEY);
    if (cached) setBikes(JSON.parse(cached));
  };

  const fetchBikes = async (pageNum = 1, isRefresh = false) => {
    try {
      if (isRefresh) setRefreshing(true);
      else if (pageNum === 1) setLoading(true);

      const res = await fetch(`/api/bikes?page=${pageNum}&limit=20`);
      if (!res.ok) throw new Error('Failed to fetch bikes');
      const data = await res.json();

      setBikes(prev => pageNum === 1 ? data.bikes : [...prev, ...data.bikes]);
      setHasMore(data.hasMore);
      setPage(pageNum);

      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(
        pageNum === 1 ? data.bikes : [...(pageNum === 1 ? [] : bikes), ...data.bikes]
      ));
    } catch (err) {
      setError(err.message || 'Something went wrong');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => { loadCached(); fetchBikes(1); }, []);

  return {
    bikes,
    loading: loading && bikes.length === 0,
    error,
    refresh: () => fetchBikes(1, true),
    loadMore: () => { if (hasMore && !loading) fetchBikes(page + 1); },
  };
}

// BikeListScreen.tsx
function BikeListScreen() {
  const { bikes, loading, error, refresh, loadMore } = useNearbyBikes();

  if (error && bikes.length === 0) return <ErrorView message={error} onRetry={refresh} />;

  return (
    <FlatList
      data={bikes}
      keyExtractor={(item) => item.id}
      renderItem={({ item }) => <BikeCard bike={item} />}
      onRefresh={refresh}
      refreshing={false}
      onEndReached={loadMore}
      onEndReachedThreshold={0.5}
      ListFooterComponent={loading ? <ActivityIndicator /> : null}
    />
  );
}
```

## Common Pitfalls
- Forgetting onEndReachedThreshold causes loadMore to fire too early or never
- Not tracking hasMore results in duplicate API calls at list end
- AsyncStorage is async—never assume immediate availability
- Missing error state causes silent failures visible only in console
- Not using keyExtractor forces FlatList to use index, causing render bugs on prepend

