## Code Example
```javascript
import { useEffect, useState, useRef } from 'react';
import { NativeModules } from 'react-native';
const { MetadataModule } = NativeModules;

export function useLazyMetadata(ids) {
  const [map, setMap] = useState({});
  const queue = useRef({ pending: new Set(), timer: null });

  useEffect(() => {
    ids.forEach(id => queue.current.pending.add(id));
    if (queue.current.timer) clearTimeout(queue.current.timer);
    queue.current.timer = setTimeout(async () => {
      const toFetch = Array.from(queue.current.pending);
      queue.current.pending.clear();
      if (MetadataModule?.fetchMetadata) {
        try {
          const result = await MetadataModule.fetchMetadata(toFetch);
          setMap(prev => ({ ...prev, ...result }));
        } catch {
          // fallback: ignore errors to keep UI responsive
        }
      } else {
        const fallback = Object.fromEntries(toFetch.map(id => [id, { placeholder: true }]));
        setMap(prev => ({ ...prev, ...fallback }));
      }
    }, 80);
  }, [ids.join(',')]);
  return map;
}
```

